#include <vector>
#include <queue>
#include <climits>
#include <utility>
#include <unordered_map>

using namespace std;

long long solve(long long n, std::vector<std::vector<long long>> edges) {
    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    // Build reverse adjacency list for incoming edges
    vector<vector<pair<long long, long long>>> rev_adj(n);
    for (const auto& e : edges) {
        long long u = e[0], v = e[1], w = e[2];
        adj[u].emplace_back(v, w);
        rev_adj[v].emplace_back(u, w);
    }

    // Dijkstra's setup: dist[0] = not used switch, dist[1] = used switch
    vector<vector<long long>> dist(2, vector<long long>(n, LLONG_MAX));
    // Priority queue: (distance, node, switch_used)
    priority_queue<tuple<long long, long long, bool>, 
                   vector<tuple<long long, long long, bool>>, 
                   greater<tuple<long long, long long, bool>>> pq;

    dist[0][0] = 0;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used] = pq.top();
        pq.pop();

        if (current_dist > dist[used][u]) continue;

        // Explore normal edges
        for (auto [v, w] : adj[u]) {
            if (dist[used][v] > current_dist + w) {
                dist[used][v] = current_dist + w;
                pq.emplace(dist[used][v], v, used);
            }
        }

        // If switch not used yet, explore reversed edges
        if (!used) {
            for (auto [v, w] : rev_adj[u]) {
                long long new_dist = current_dist + 2 * w;
                if (dist[true][v] > new_dist) {
                    dist[true][v] = new_dist;
                    pq.emplace(new_dist, v, true);
                }
            }
        }
    }

    long long res = min(dist[0][n-1], dist[1][n-1]);
    return res == LLONG_MAX ? -1 : res;
}

