                if (dist[used][v] > currentDist + w) {
                    dist[used][v] = currentDist + w;
                    pq.offer(new long[]{dist[used][v], v, used});
                }
            }

            // If switch not used yet, explore reversed edges
            if (used == 0) {
                for (long[] edge : revAdj.get(u)) {
                    int v = (int) edge[0];
                    long w = edge[1];
