                    if (dist[1][v] > newDist) {
                        dist[1][v] = newDist;
                        pq.offer(new long[]{dist[1][v], v, 1});
                    }
                }
            }
        }

        long res = Math.min(dist[0][numNodes - 1], dist[1][numNodes - 1]);
        return res == Long.MAX_VALUE ? -1 : res;
    }
}
